"""
MKT Christ Commentary — Job chapters 33–35
Run: python3 scripts/zc-christ-job-33-35.py
Key connections:
- Job 33:4  -> Gen 2:7 / John 20:22 (Spirit/breath of God; new creation breath)
- Job 33:6  -> Heb 2:17 (Elihu as clay-man standing before God anticipates the true Mediator)
- Job 33:23 -> 1 Tim 2:5 / Heb 7:25 (meliṣ mediator one-in-a-thousand; Christ the one mediator)
- Job 33:24 -> Mark 10:45 / Heb 9:15 (koper ransom; Christ the ransom for many)
- Job 33:25-26 -> Tit 3:5 / John 3:3 (flesh fresher than child's; born again; resurrection restoration)
- Job 34:11 -> 2 Cor 5:10 / Rev 20:12 (repays each according to work; gospel exceeds mere retribution)
- Job 34:14-15 -> Heb 1:3 / Col 1:17 (withdraws Spirit, all perish; Christ sustains creation)
- Job 34:29 -> Rom 8:33-34 (when God is quiet who can condemn? Christ is the one who died)
- Job 35:10 -> Acts 16:25 (songs in the night; Paul and Silas singing in prison)
- Job 35:13 -> Heb 5:7 (God hears genuine cry; Christ's cry from cross)
"""

import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

new_data = {
    "33": {
        "1": "<p>Elihu speaks directly to Job &#8212; a shift from the three friends who addressed each other and the audience. Christ also speaks directly and personally to the individual (John&#160;11:23: &#8220;Your brother will rise again&#8221;; John&#160;20:16: &#8220;Mary&#8221;). The personal address is the mark of genuine mediation.</p>",
        "2": "<p>Elihu has opened his mouth; his tongue speaks within his mouth. The self-announcement of the speaker prepares for the greater announcement: the Word made flesh (John&#160;1:14), the one whose speech comes not from a human mouth alone but from the Father who sent him (John&#160;12:49).</p>",
        "3": "<p>Words from an upright heart; lips speak what he knows sincerely. Elihu&#8217;s claim of integrity anticipates Christ&#8217;s perfect sincerity: &#8220;the words that I say to you I do not speak on my own authority, but the Father who dwells in me does his works&#8221; (John&#160;14:10). Christ&#8217;s words are perfectly aligned with his character.</p>",
        "4": "<p>&#8220;The Spirit of God has made me, and the breath of the Almighty gives me life.&#8221; Elihu acknowledges his creaturely dependence on the divine breath &#8212; the same <i>n&#353;māh</i> of Gen&#160;2:7. Christ&#8217;s resurrection is the new creation: he breathes on his disciples (John&#160;20:22), giving the Holy Spirit &#8212; the life-giving breath now becomes the Spirit of new creation.</p>",
        "5": "<p>If you can answer me, set your words in order before me and take your stand. The call to make a case &#8212; and then present Christ as the one whose case stands without defect: 1&#160;Pet&#160;3:15 &#8220;always be prepared to make a defense to anyone who asks you for a reason for the hope that is in you.&#8221; Christ is both the advocate and the one whose case cannot be refuted (John&#160;8:46: &#8220;which one of you convicts me of sin?&#8221;).</p>",
        "6": "<p>&#8220;See, I stand before God on your behalf as you wished; I too was formed from clay.&#8221; Elihu&#8217;s claim to be a fellow-creature who stands before God on Job&#8217;s behalf is the imperfect anticipation of Christ, who is also &#8220;made from dust&#8221; in the Incarnation (Phil&#160;2:7: &#8220;born in the likeness of men&#8221;) and stands before the Father as humanity&#8217;s representative (Heb&#160;2:17: &#8220;he had to be made like his brothers in every respect... to make propitiation for the sins of the people&#8221;).</p>",
        "7": "<p>My dread will not terrify you; my pressure will not be heavy upon you. The gentle approach of the true mediator &#8212; Christ who says &#8220;my yoke is easy and my burden is light&#8221; (Matt&#160;11:30) and &#8220;do not be afraid&#8221; (John&#160;6:20). Unlike the approach to Sinai (Heb&#160;12:18&#8211;21), the approach through Christ brings confidence not terror.</p>",
        "8": "<p>Elihu reports what Job said &#8212; the careful listening that precedes a genuine answer. Christ also hears before he speaks: Heb&#160;5:7 &#8220;in the days of his flesh, Jesus offered up prayers and supplications with loud cries and tears to him who was able to save him from death, and he was heard because of his reverence.&#8221;</p>",
        "9": "<p>&#8220;You said: I am clean, without transgression; I am innocent and there is no iniquity in me.&#8221; Job&#8217;s claim of innocence, which is contested by the friends, is ultimately vindicated by God (42:7). But Christ&#8217;s claim of sinlessness is not contested &#8212; it is absolute: &#8220;In him there is no sin&#8221; (1&#160;John&#160;3:5); &#8220;one who in every respect has been tempted as we are, yet without sin&#8221; (Heb&#160;4:15).</p>",
        "10": "<p>But God finds grievances against me; regards me as his enemy. The estrangement Job experiences &#8212; God as adversary &#8212; is what Christ absorbs at the cross. He becomes the enemy of God on behalf of those who were God&#8217;s enemies (Rom&#160;5:10: &#8220;while we were enemies we were reconciled to God by the death of his Son&#8221;).</p>",
        "11": "<p>He puts my feet in stocks; he watches all my paths. The prisoner-of-God image. Christ is himself the prisoner at his arrest (John&#160;18:12) &#8212; the free one bound so that the bound might go free. His paths are watched by the Father because they lead infallibly to redemption.</p>",
        "12": "<p>&#8220;In this I tell you plainly that you are wrong: God is greater than any human being.&#8221; The divine greatness that exceeds human comprehension is the point where Elihu&#8217;s theology is correct &#8212; and it is the premise of the Incarnation: only one who is greater than any human being could be the mediator that both Job and the cosmos need (1&#160;Tim&#160;2:5: &#8220;one mediator between God and men, the man Christ Jesus&#8221;).</p>",
        "13": "<p>Why do you argue against him? He does not give account for any of his actions. The inscrutable freedom of God that exceeds all human questioning &#8212; and yet: the cross is God&#8217;s self-account, his explanation, his justification of his own ways (Rom&#160;3:25&#8211;26: &#8220;it was to show his righteousness at the present time, so that he might be just and the justifier of the one who has faith in Jesus&#8221;).</p>",
        "14": "<p>God speaks in one way and then another, though people do not notice. The various modes of divine revelation enumerated here (dreams, visions, chastening) all anticipate the final speech: Heb&#160;1:1&#8211;2 &#8220;Long ago, at many times and in many ways, God spoke to our fathers by the prophets, but in these last days he has spoken to us by his Son.&#8221;</p>",
        "15": "<p>In a dream, in a nighttime vision, when deep sleep falls on people. God speaks through the unconscious, reaching the person when all defenses are down. The incarnation is the most direct form of this speaking: God entering the full human condition &#8212; including the vulnerability of sleep (Matt&#160;8:24: Jesus sleeps in the boat; Luke&#160;2:7: the infant sleeps).</p>",
        "16": "<p>He opens people&#8217;s ears and confirms what he is teaching them. The opened ear of the disciple: Isa&#160;50:4&#8211;5 &#8220;morning by morning he wakens my ear to hear as those who are taught&#8221; &#8212; the Servant of the LORD whose ear is opened is the pattern Christ embodies; and he opens the disciples&#8217; understanding (Luke&#160;24:45).</p>",
        "17": "<p>To turn them from their intended course and shield them from pride. The purpose of divine discipline: turning and humbling. Christ&#8217;s teaching also turns people from the way of destruction (Matt&#160;7:13&#8211;14) and his cross is the supreme destruction of human pride (1&#160;Cor&#160;1:29: &#8220;so that no human being might boast in the presence of God&#8221;).</p>",
        "18": "<p>He keeps him from the pit and his life from crossing into death. God&#8217;s preserving purpose in suffering. The ultimate keeping-from-the-pit is the resurrection of Christ: Acts&#160;2:24 &#8220;God raised him up, loosing the pangs of death, because it was not possible for him to be held by it&#8221; (citing Ps&#160;16:10: &#8220;you will not abandon my soul to Sheol&#8221;).</p>",
        "19": "<p>Chastened with pain upon his bed; unending conflict in his bones. Elihu describes the physical suffering of God&#8217;s discipline. Heb&#160;5:8: &#8220;although he was a son, he learned obedience through what he suffered.&#8221; Christ himself is the suffering-and-learning servant, though his suffering is not punitive but redemptive.</p>",
        "20": "<p>He cannot eat bread; appetite revolts against any food. The fast of suffering. Jesus himself fasted forty days (Matt&#160;4:2) and on the cross refused the drugged wine (Mark&#160;15:23). He abstained from earthly sustenance to accomplish the work of redemption, offering himself as the true bread (John&#160;6:51).</p>",
        "21": "<p>His flesh wastes away until it is gone; bones that were hidden now protrude. The bodily dissolution of extreme suffering. The crucified Christ: John&#160;19:34 (blood and water from his side); Ps&#160;22:14&#8211;17 (bones out of joint, strength dried up, feet and hands pierced) &#8212; the Passion Psalm describes this exact wasting.</p>",
        "22": "<p>His life draws near the pit and his soul to the agents of death. The proximity to death &#8212; and then the mediator arrives. Christ descended to the deepest point &#8212; Eph&#160;4:9 &#8220;he had also descended into the lower parts of the earth&#8221; &#8212; so that his rescue could reach those nearest the pit.</p>",
        "23": "<p>&#8220;But if there is a messenger for him, a mediator (<i>meli&#7779;</i>) &#8212; one in a thousand &#8212; who declares to the person their uprightness.&#8221; This is the book&#8217;s most explicit mediator-term outside 19:25. The <i>meli&#7779;</i> (interpreter, messenger, mediator) who is one-in-a-thousand finds its fulfilment in Christ: &#8220;there is one mediator between God and men, the man Christ Jesus&#8221; (1&#160;Tim&#160;2:5). He alone, of all possible advocates, both declares the person&#8217;s uprightness and has grounds to do so.</p>",
        "24": "<p>&#8220;Then God is gracious to him and says: Spare him from going down to the pit; I have found a ransom (<i>k&#333;per</i>).&#8221; The ransom-declaration from God is the theological heart of the chapter. Mark&#160;10:45: &#8220;the Son of Man came not to be served but to serve, and to give his life as a ransom (<i>lytron</i>) for many.&#8221; Heb&#160;9:15: Christ &#8220;is the mediator of a new covenant, so that those who are called may receive the promised eternal inheritance, since a death has occurred that redeems them from the transgressions committed under the first covenant.&#8221; The ransom God finds is his own Son.</p>",
        "25": "<p>&#8220;His flesh becomes fresher than a child&#8217;s; he is restored to the days of his youth.&#8221; The restoration through the mediator&#8217;s ransom &#8212; a new-creation freshness beyond the original state. Tit&#160;3:5: &#8220;he saved us through the washing of regeneration and renewing of the Holy Spirit.&#8221; John&#160;3:3: &#8220;unless one is born again he cannot see the kingdom of God.&#8221; The born-again metaphor is the new-covenant form of the flesh-fresher-than-a-child image Elihu describes.</p>",
        "26": "<p>&#8220;He prays to God and God accepts him; he sees his face with a shout of joy, and God restores his righteousness to him.&#8221; The restoration pattern: prayer, acceptance, sight-of-God, righteousness restored. 1&#160;John&#160;3:2: &#8220;when he appears we shall be like him, because we shall see him as he is.&#8221; The face-to-face vision is the eschatological goal, secured through the mediator&#8217;s ransom.</p>",
        "27": "<p>He looks on people and says: &#8220;I sinned and bent what was right, and it brought me nothing.&#8221; The confession that follows rescue rather than preceding it &#8212; the person acknowledges sin in the light of grace. 1&#160;John&#160;1:9: &#8220;if we confess our sins, he is faithful and just to forgive us our sins and to cleanse us from all unrighteousness.&#8221; The confession that brings forgiveness is possible only because the ransom has been paid.</p>",
        "28": "<p>&#8220;God will deliver his life from the pit, and his life will see the light.&#8221; The seeing-of-light after rescue from the pit is the resurrection pattern. John&#160;1:4&#8211;5: &#8220;in him was life, and the life was the light of men. The light shines in the darkness, and the darkness has not overcome it.&#8221; The pit cannot hold the one the mediator has ransomed.</p>",
        "29": "<p>God does all these things &#8212; again and again &#8212; with a person. The repeated, patient, redeeming work of God. 2&#160;Pet&#160;3:9: &#8220;the Lord is not slow to fulfill his promise as some count slowness, but is patient toward you, not wishing that any should perish, but that all should reach repentance.&#8221; The cross is the once-for-all event that grounds the again-and-again patience.</p>",
        "30": "<p>To bring his life back from the pit, that he might be lit by the light of the living. The purpose of redemption: not merely rescue from death but lighting-up by life. Christ as &#8220;the resurrection and the life&#8221; (John&#160;11:25) brings those rescued from the pit into a new quality of existence &#8212; the light of the living that is nothing less than Christ himself (John&#160;8:12).</p>",
        "31": "<p>Pay close attention, Job; be silent and I will speak. The invitation to listening silence before the mediator&#8217;s word. Heb&#160;1:2 God &#8220;has spoken to us by his Son&#8221; &#8212; the final word that requires the silence of all other speech, the attentive listening of faith.</p>",
        "32": "<p>If you have anything to say, answer me; speak up, for I want to see you vindicated. Elihu genuinely desires Job&#8217;s vindication &#8212; not his condemnation. Christ, the perfect Mediator, desires the vindication of all who come to him: &#8220;whoever comes to me I will never cast out&#8221; (John&#160;6:37); &#8220;I did not come to judge the world but to save the world&#8221; (John&#160;12:47).</p>",
        "33": "<p>If not, listen to me; be silent, and I will teach you wisdom. The teaching of wisdom to the silent one. Matt&#160;11:29: &#8220;take my yoke upon you and learn from me, for I am gentle and lowly in heart, and you will find rest for your souls.&#8221; The wisdom Christ teaches is himself &#8212; the one the wisdom poem of ch.&#160;28 was searching for.</p>"
    },
    "34": {
        "1": "<p>Elihu shifts audience &#8212; from Job to the wise men in the assembly. Christ also modulates his teaching audience (crowds, disciples, Pharisees, individuals) without modifying his message. The gospel is for all who have ears to hear (Matt&#160;13:9).</p>",
        "2": "<p>Hear my words, O wise men; listen to me, you who have knowledge. 1&#160;Cor&#160;1:26&#8211;27: &#8220;not many of you were wise according to worldly standards... God chose what is foolish in the world to shame the wise.&#8221; The audience Elihu addresses &#8212; the wise and knowledgeable &#8212; are precisely those who find the cross a stumbling block (1&#160;Cor&#160;1:23).</p>",
        "3": "<p>For the ear tests words as the palate tastes food. The discernment of speech: 1&#160;Cor&#160;2:15 &#8220;the spiritual person judges all things, but is himself to be judged by no one.&#8221; Christ&#8217;s words are the standard by which all other words are tested: John&#160;12:48 &#8220;the word that I have spoken will judge him on the last day.&#8221;</p>",
        "4": "<p>Let us choose together what is right. The communal discernment process that Elihu proposes &#8212; but true discernment requires the Spirit: 1&#160;Cor&#160;2:10&#8211;11 &#8220;the Spirit searches everything, even the depths of God.&#8221; The right that is truly right is revealed in Christ who is himself righteousness (1&#160;Cor&#160;1:30).</p>",
        "5": "<p>For Job has said, &#8220;I am righteous, and God has denied me my right.&#8221; Elihu summarizes Job&#8217;s complaint accurately. God&#8217;s ultimate answer is not to deny Job&#8217;s claim but to vindicate it (42:7) &#8212; and the cross is the place where God proves he does not deny the right of the innocent: he vindicates them through resurrection.</p>",
        "6": "<p>Must I lie about my case? My wound is past healing though I have done no wrong. The wound of the innocent sufferer that surpasses human healing &#8212; this is the condition Christ enters. Isa&#160;53:5: &#8220;by his wounds we are healed&#8221; &#8212; the wound that is past human healing becomes the source of healing for all.</p>",
        "7": "<p>What man is like Job, who drinks mockery like water? The exceptional sufferer who endures mockery as if it were daily drink. Ps&#160;69:21: &#8220;they gave me poison for food, and for my thirst they gave me sour wine to drink&#8221; &#8212; applied in John&#160;19:29 to Christ who literally drank the sour wine of mockery on the cross.</p>",
        "8": "<p>Who keeps company with evildoers and walks with wicked men. The accusation against Job &#8212; which is also the accusation against Jesus: &#8220;this man receives sinners and eats with them&#8221; (Luke&#160;15:2). The one who walks with the wicked to redeem them is not contaminated but transforms them.</p>",
        "9": "<p>For Job said, &#8220;A man gains nothing by delighting in God.&#8221; Elihu quotes Job at his worst moment. But Christ&#8217;s resurrection is God&#8217;s refutation of this despair: &#8220;your labor in the Lord is not in vain&#8221; (1&#160;Cor&#160;15:58); the delight in God that Job doubts in extremis is vindicated by Easter.</p>",
        "10": "<p>&#8220;Far be it from God to do evil, far from the Almighty to do wrong.&#8221; The moral purity of God that undergirds the cross: God was not unjust in punishing Christ; he was satisfying justice on behalf of sinners who could not satisfy it themselves. Rom&#160;3:25&#8211;26: the cross demonstrates that God is &#8220;just and the justifier of the one who has faith in Jesus.&#8221;</p>",
        "11": "<p>He repays each person according to their work and deals with everyone according to their conduct. The justice principle: 2&#160;Cor&#160;5:10; Rev&#160;20:12. But the gospel exceeds mere retribution &#8212; Rom&#160;4:5&#8211;6 credits Christ&#8217;s righteousness to the one who does not work but trusts. The one who repays according to works takes the penalty himself in Christ.</p>",
        "12": "<p>Of a truth, God will not act wickedly; the Almighty will not pervert justice. The cross is the proof: God did not pervert justice by letting sin go unpunished. Rom&#160;3:26: &#8220;at the present time his righteousness might be demonstrated, so that he might be just and the justifier.&#8221; The cross satisfies justice; it does not bypass it.</p>",
        "13": "<p>Who gave God his charge over the earth? Who appointed him over the whole world? The rhetorical questions assert God&#8217;s aseity and sovereign lordship. Col&#160;1:16: &#8220;by him all things were created... all things were created through him and for him.&#8221; God owns creation because he made it; and Christ is both the Creator and the appointed heir (Heb&#160;1:2).</p>",
        "14": "<p>&#8220;If he should set his heart against us and gather to himself his Spirit and breath.&#8221; The contingency of all creaturely life on continued divine sustenance. Heb&#160;1:3: Christ &#8220;upholds the universe by the word of his power.&#8221; Col&#160;1:17: &#8220;in him all things hold together.&#8221; The withdrawal Elihu imagines is the condition that only Christ&#8217;s sustaining prevents.</p>",
        "15": "<p>All flesh would perish together; human beings would return to dust. The fragility of existence without continuous divine support. Christ as the one in whom all things consist (Col&#160;1:17) is the answer to this fragility &#8212; and his own resurrection from the dust is the pledge that human bodies will not be abandoned to it permanently (1&#160;Cor&#160;15:42&#8211;44).</p>",
        "16": "<p>If you have understanding, hear this; listen to what I am saying. The summons to understanding &#8212; which comes finally not from Elihu but from the divine speech and ultimately from Christ who gives understanding: Luke&#160;24:45 &#8220;then he opened their minds to understand the Scriptures.&#8221;</p>",
        "17": "<p>&#8220;Shall one who hates justice govern? Will you condemn the One who is righteous and mighty?&#8221; The rhetorical challenge anticipates the accusations against Christ: Pilate&#8217;s verdict (&#8220;I find no fault in him&#8221;) and the crowd&#8217;s condemnation represent the condemning of the one who is righteous. But Isa&#160;9:7: &#8220;of the increase of his government and peace there will be no end&#8221; &#8212; the righteous and mighty one does govern.</p>",
        "18": "<p>Is it right to say to a king, &#8220;You are worthless,&#8221; and to nobles, &#8220;You are wicked&#8221;? How much less is it right to accuse God? At the crucifixion the soldiers mocked: &#8220;Hail, King of the Jews&#8221; (John&#160;19:3) with contempt. But Phil&#160;2:9&#8211;11 declares that this king will be acknowledged without ambiguity by every tongue.</p>",
        "19": "<p>He shows no partiality to princes and does not favor the rich over the poor, for they are all his handiwork. Acts&#160;10:34: &#8220;God shows no partiality.&#8221; The cross is for all: John&#160;3:16 &#8220;God so loved the world&#8221; &#8212; not one class or nation. The gospel reaches both the thief on the cross and the Roman centurion who guards him.</p>",
        "20": "<p>In a moment they die; at midnight the people are convulsed and pass away; the mighty are removed without hand. The sudden reversals of death &#8212; Christ promises the same reversal in reverse: at his return the dead in Christ will be raised &#8220;in a moment, in the twinkling of an eye&#8221; (1&#160;Cor&#160;15:52).</p>",
        "21": "<p>His eyes are on the ways of everyone; he sees all their steps. Heb&#160;4:13: &#8220;no creature is hidden from his sight, but all are naked and exposed to the eyes of him to whom we must give account.&#8221; This omniscience makes both judgment inescapable and rescue certain &#8212; God sees the suffering of the afflicted (v28) and the wickedness of oppressors with equal clarity.</p>",
        "22": "<p>There is no darkness or deep shadow where evildoers can hide themselves. The absolute transparency before God. John&#160;3:20: &#8220;everyone who does wicked things hates the light and does not come to the light, lest his works should be exposed.&#8221; Christ is the light that unmasks &#8212; and also the grace that forgives when the exposed person comes (1&#160;John&#160;1:7).</p>",
        "23": "<p>He does not impose on anyone more than is warranted to bring them before God in judgment. God&#8217;s measured justice &#8212; the cross is the most precise expression of this: &#8220;the wages of sin is death&#8221; (Rom&#160;6:23), and Christ bore exactly what was warranted, no more and no less. God&#8217;s justice is not arbitrary but precisely proportional.</p>",
        "24": "<p>He shatters the mighty without investigation and sets others in their place. The divine reversals of power that the incarnation executes: Luke&#160;1:52 &#8220;he has brought down the mighty from their thrones and exalted those of humble estate&#8221; &#8212; the Magnificat&#8217;s announcement of the reversal that Christ&#8217;s coming enacts.</p>",
        "25": "<p>He knows their deeds and overturns them in the night; they are crushed. The night of crucifixion is both the darkest night and the moment of the decisive overturn: John&#160;13:27 &#8220;what you are going to do, do quickly&#8221; &#8212; Judas goes out and &#8220;it was night&#8221; (13:30). But the one crushed rises; the night of his death becomes the dawn of resurrection.</p>",
        "26": "<p>He strikes them for their wickedness in an open place where others can see. The public nature of divine judgment. Christ&#8217;s crucifixion was public &#8212; outside the city gate (Heb&#160;13:12), on a hill visible to all &#8212; where the bearing of the world&#8217;s sin was enacted not in secret but in full view.</p>",
        "27": "<p>Because they turned away from following him and gave no thought to any of his ways. The root of judgment is departure from God. The cross is God&#8217;s call-back: &#8220;Come to me, all who labor and are heavy laden&#8221; (Matt&#160;11:28); &#8220;I, when I am lifted up from the earth, will draw all people to myself&#8221; (John&#160;12:32). The one from whom people turn away now draws them to himself.</p>",
        "28": "<p>&#8220;So that they brought the cry of the poor before him, and he heard the outcry of the afflicted.&#8221; God hears the cry of the poor. Luke&#160;4:18: &#8220;he has anointed me to proclaim good news to the poor.&#8221; Matt&#160;25:40: &#8220;as you did it to one of the least of these my brothers, you did it to me.&#8221; The divine hearing of the afflicted culminates in Christ who is himself afflicted on their behalf.</p>",
        "29": "<p>&#8220;When he is quiet, who can condemn? When he hides his face, who can see him?&#8221; The question that anticipates Paul&#8217;s answer: Rom&#160;8:33&#8211;34 &#8220;who shall bring any charge against God&#8217;s elect? It is God who justifies. Who is to condemn? Christ Jesus is the one who died &#8212; more than that, who was raised, who is at the right hand of God, who indeed is interceding for us.&#8221; When God is at peace with us through Christ, no condemnation can stand.</p>",
        "30": "<p>Lest a godless person reign and ensnare the people. The threat of ungodly rule. Christ is the ruler who does not ensnare but liberates: John&#160;8:36 &#8220;if the Son sets you free, you will be free indeed.&#8221; Rev&#160;20:10: the ultimate ensnarer &#8212; the devil &#8212; is thrown into the lake of fire; Christ&#8217;s reign excludes the godless one.</p>",
        "31": "<p>Has anyone said to God, &#8220;I have endured my punishment; I will not sin any more&#8221;? The posture of repentance before God. Luke&#160;15:18&#8211;19: &#8220;I will arise and go to my father, and I will say to him, Father, I have sinned against heaven and before you.&#8221; Christ&#8217;s parable depicts the Father running to receive this confession &#8212; grace meets the returning penitent.</p>",
        "32": "<p>&#8220;Teach me what I cannot see; if I have done wrong, I will not do it again.&#8221; The teachable heart that asks God to reveal its blind spots. John&#160;16:8: the Spirit &#8220;will convict the world concerning sin and righteousness and judgment&#8221; &#8212; Christ sends the Spirit who teaches what we cannot see and enables the repentance Elihu envisions.</p>",
        "33": "<p>Should God repay on your terms because you reject his? For you must choose. The ultimacy of the choice: Josh&#160;24:15 &#8220;choose this day whom you will serve&#8221;; Rev&#160;22:17 &#8220;let the one who is thirsty come; let the one who desires take the water of life without price.&#8221; Christ does not force; he offers &#8212; and the choice is ours.</p>",
        "34": "<p>People of understanding will agree with me; every wise person who hears me will say. The consensus of the wise &#8212; but 1&#160;Cor&#160;1:20&#8211;21: &#8220;where is the wise person?... God made foolish the wisdom of the world. For since, in the wisdom of God, the world did not know God through wisdom, it pleased God through the folly of what we preach to save those who believe.&#8221;</p>",
        "35": "<p>&#8220;Job speaks without knowledge; his words are without insight.&#8221; Elihu&#8217;s condemnation is too harsh &#8212; God himself overturns this verdict in ch.&#160;42. Christ&#8217;s verdicts are the ones that stand: &#8220;blessed are the pure in heart&#8221; (Matt&#160;5:8); &#8220;well done, good and faithful servant&#8221; (Matt&#160;25:21). The final judgment of a life belongs to God alone.</p>",
        "36": "<p>Would that Job were tested to the limit, because his answers are like those of wicked men. Elihu&#8217;s excessive accusation. Christ is the one who is tested to the limit (Matt&#160;4:1&#8211;11; Heb&#160;4:15) and comes through without sin &#8212; demonstrating that the test can be endured in the power God provides.</p>",
        "37": "<p>For he adds rebellion to his sin; he mocks us and heaps up words against God. The final overreach of Elihu&#8217;s accusation. But God&#8217;s verdict in 42:7 shows that Job &#8220;spoke what is right.&#8221; Christ is the perfect judge of the heart (John&#160;2:25) whose verdicts are not overturned.</p>"
    },
    "35": {
        "1": "<p>Elihu continues. The speech now turns to the question of whether human behavior affects God &#8212; a question the Incarnation answers definitively: God is affected by human sin, not in the sense of being diminished, but in the sense that he chose to bear it (2&#160;Cor&#160;5:21).</p>",
        "2": "<p>&#8220;Do you think this is just when you say, &#8216;My righteousness is more than God&#8217;s&#8217;?&#8221; Elihu&#8217;s framing of Job&#8217;s complaint. The ultimate answer to the comparison between divine and human righteousness is Christ, who is both &#8212; divine righteousness incarnate (Rom&#160;1:17) and the source of human righteousness by faith (Rom&#160;3:22).</p>",
        "3": "<p>You say, &#8220;What does it benefit you? What do I gain from not sinning?&#8221; The cynical question that emptiness can produce. The resurrection answers it: &#8220;your labor in the Lord is not in vain&#8221; (1&#160;Cor&#160;15:58). The gain of righteousness is Christ himself &#8212; the surpassing worth of knowing him (Phil&#160;3:8).</p>",
        "4": "<p>I will give you an answer, and your companions along with you. Elihu speaks to both Job and the friends. Christ speaks to the individual and to the community simultaneously: Heb&#160;4:12 &#8220;the word of God is living and active, sharper than any two-edged sword,&#8221; piercing to the thoughts and intentions of every individual heart.</p>",
        "5": "<p>Look up at the sky and see; behold the clouds, higher than you. The call to lift the gaze heavenward. Heb&#160;12:2: &#8220;looking to Jesus, the founder and perfecter of our faith.&#8221; The upward look is to the ascended Christ who has gone higher than the clouds &#8212; &#8220;exalted above the heavens&#8221; (Heb&#160;7:26).</p>",
        "6": "<p>If you sin, what do you accomplish against him? Elihu&#8217;s point about divine transcendence. But the Incarnation precisely reverses this: in Christ, God IS affected by human sin &#8212; Isa&#160;53:4 &#8220;he has borne our griefs and carried our sorrows.&#8221; The transcendent God becomes the one who absorbs sin&#8217;s consequences.</p>",
        "7": "<p>If you are righteous, what do you give him? What does he receive from your hand? The question of what humans can offer God &#8212; which is nothing self-generated. 2&#160;Cor&#160;5:21: &#8220;for our sake he made him to be sin who knew no sin, so that in him we might become the righteousness of God.&#8221; Christ gives the Father what humans cannot: perfect righteousness, on behalf of those who have none.</p>",
        "8": "<p>Your wickedness harms only someone like yourself; your righteousness benefits only other people. The horizontal consequences of sin and righteousness. But Christ&#8217;s righteousness has a vertical dimension: it accomplishes what no human righteousness could &#8212; the reconciliation of Creator and creature (Col&#160;1:20).</p>",
        "9": "<p>Under the weight of great oppression people cry out; they call for help from the arm of the powerful. The universal human cry under oppression. Luke&#160;4:18&#8211;19: &#8220;he has sent me to proclaim release to the captives... to set at liberty those who are oppressed, to proclaim the year of the Lord&#8217;s favor.&#8221; Christ is the arm of the powerful who responds to this cry.</p>",
        "10": "<p>&#8220;But no one asks, &#8216;Where is God my Maker, who gives songs in the night?&#8217;&#8221; The deeper question that the oppressed fail to ask. Acts&#160;16:25: Paul and Silas in prison at midnight, singing hymns to God &#8212; the literal enactment of songs-in-the-night. Christ gives the capacity to sing in prison that Elihu identifies as the mark of true knowledge of God.</p>",
        "11": "<p>Who teaches us more than the animals of the earth and makes us wiser than the birds of the sky. The divine teaching that elevates humanity beyond the rest of creation. Matt&#160;11:29: &#8220;take my yoke upon you and learn from me.&#8221; Col&#160;2:3: &#8220;in him are hidden all the treasures of wisdom and knowledge.&#8221; Christ is the teacher who makes the disciple wiser than all natural wisdom.</p>",
        "12": "<p>There they cry, but he does not answer, because of the pride of evil people. The unanswered cry of those who cry from wrong motives &#8212; pride rather than genuine need. Jas&#160;4:6: &#8220;God opposes the proud but gives grace to the humble.&#8221; Christ&#8217;s answer is to those who humble themselves &#8212; &#8220;everyone who exalts himself will be humbled, and everyone who humbles himself will be exalted&#8221; (Luke&#160;14:11).</p>",
        "13": "<p>Certainly God does not hear a hollow cry; the Almighty does not regard it. The authentic cry that God does hear: Heb&#160;5:7 &#8220;in the days of his flesh, Jesus offered up prayers and supplications with loud cries and tears to him who was able to save him from death, and he was heard because of his reverence.&#8221; Christ&#8217;s cry is the most genuine cry ever made &#8212; and Ps&#160;22:24 confirms God heard it: &#8220;he has not despised or scorned the suffering of the afflicted one.&#8221;</p>",
        "14": "<p>How much less when you say you cannot see him, that the case is before him, and you must wait for him. The counsel to wait in trust. Heb&#160;6:15: &#8220;Abraham, having patiently waited, obtained the promise.&#8221; The waiting and trusting that Elihu recommends is fulfilled in Christ who &#8220;endured the cross, despising the shame, and is seated at the right hand of the throne of God&#8221; (Heb&#160;12:2).</p>",
        "15": "<p>But now, because God has not punished in his anger and does not take sharp notice of every transgression &#8212; The patience of God before judgment: 2&#160;Pet&#160;3:9: &#8220;the Lord is not slow to fulfill his promise as some count slowness, but is patient toward you, not wishing that any should perish, but that all should reach repentance.&#8221; The delay of punishment is grace extended; it finds its ultimate expression in the cross where sin is dealt with once for all.</p>",
        "16": "<p>&#8220;So Job opens his mouth with empty words; he heaps up words without knowledge.&#8221; The final judgment on Job by Elihu &#8212; which God himself overturns in ch.&#160;42 (&#8220;Job has spoken what is right&#8221;). Christ is the one whose words are never empty: John&#160;6:63 &#8220;the words that I have spoken to you are spirit and life.&#8221; He is the Word without emptiness, knowledge without limit.</p>"
    }
}

existing = load_comm('mkt-christ', 'job')
merge_comm(existing, new_data)
save_comm('mkt-christ', 'job', existing)

for ch in sorted(new_data.keys(), key=int):
    vv = new_data[ch]
    have = sum(1 for v in vv if v in existing.get(ch, {}))
    print(f'  ch{ch}: {have}/{len(vv)} verses present')
